    private void approveBtnActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_approveBtnActionPerformed
        Sound s = new Sound();
        BankFunction BF = new BankFunction();
        double total = 0;
        //String databaseURL = "jdbc:ucanaccess://C:\\Users\\User\\Documents\\NetBeansProjects\\UNION BANK SYSTEM\\src\\database\\Userdb.accdb";
       String databaseURL = "jdbc:ucanaccess://src\\database\\Userdb.accdb";
      
         String accNum=txtField_AccountNumber.getText();
         String depAmtStr=txtField_DepositAmount.getText();
         
        if(accNum.isEmpty() || depAmtStr.isEmpty()){
            s.ErrorSound();
            JOptionPane.showMessageDialog(this, "Please ensure that the account number and deposit amount are not empty!");
        }else if(Double.parseDouble(depAmtStr)<0){
            s.ErrorSound();
            JOptionPane.showMessageDialog(this, "Please ensure that the deposit amount is a valid value!");
       }else if(Double.parseDouble(depAmtStr)>0){
          double depAmt=Double.parseDouble(depAmtStr);
        try (Connection connection = DriverManager.getConnection(databaseURL)) {
            String cs = "SELECT * from Account WHERE accountNumber = ? ";
            boolean checkid = BF.CheckID(connection,accNum);
            PreparedStatement us = connection.prepareStatement(cs);
            us.setString(1,accNum)  ;        
            ResultSet rs = us.executeQuery();
            if(checkid==false){
                s.ErrorSound();
                JOptionPane.showMessageDialog(this,"Invalid account number!\nPlease try again!");
                DepositMenu dm = new DepositMenu();
                dm.setVisible(true);
                this.dispose();
            }
            s.SuccessSound();
                while(rs.next()){
                    double bal = rs.getDouble("balance"); 
                total=bal+depAmt;
                if(total<0){
                    JOptionPane.showMessageDialog(this,"The current amount of"+accNum+" is not enought!");
                    DepositMenu dm = new DepositMenu();
                    dm.setVisible(true);
                    this.dispose();
                }
            us.executeQuery();
            String sqlUsAcc = "UPDATE Account SET balance = ? WHERE accountNumber = ? ";
            PreparedStatement usAcc = connection.prepareStatement(sqlUsAcc);
            usAcc.setDouble(1, total);
            usAcc.setString(2, accNum);            
            usAcc.executeUpdate();
            
            JOptionPane.showMessageDialog(this,"The current amount of "+accNum+" is RM" + total+".");
            JOptionPane.showMessageDialog(this,"If you want to enter another deposit, please click the DEPOSIT button again.");
            OptionMenu om = new OptionMenu();
            om.setVisible(true);
            this.dispose();
            connection.close();
                }
                    
        }catch (Exception e){
                System.err.println("Got an exception!");
              
                e.printStackTrace();
                
                System.out.println(e); 
            }
       }
       
    }//GEN-LAST:event_approveBtnActionPerformed

