    private void checkAccountBtnActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_checkAccountBtnActionPerformed
        Sound s = new Sound();
        BankFunction BF = new BankFunction();
        String inacc=txtField_AccountNumber.getText();
        if(inacc.isEmpty()){
          s.ErrorSound();
          JOptionPane.showMessageDialog(this,"The account number should not be empty");
        }else{
        //String databaseURL = "jdbc:ucanaccess://C:\\Users\\User\\Documents\\NetBeansProjects\\UNION BANK SYSTEM\\src\\database\\Userdb.accdb";
        String databaseURL = "jdbc:ucanaccess://src\\database\\Userdb.accdb";
        try (Connection connection = DriverManager.getConnection(databaseURL)) {
            
                String sql = "select * from Account WHERE accountNumber = ? ";
                PreparedStatement us = connection.prepareStatement(sql);                
                us.setString(1,inacc); 
                ResultSet result = us.executeQuery();
                    while(result.next()){
                        double bal=result.getDouble("balance");
                        System.out.println(bal);
                        String acc=result.getString("accountNumber");
                   
                        currentAmount.setText("RM"+(BF.decimalFormat(bal)));
                    JOptionPane.showMessageDialog(this,"The amount for "+acc+" is: RM"+BF.decimalFormat(bal));                          
}
                 connection.close();  
                }catch (Exception e){
                System.err.println("Got an exception!");
              
                e.printStackTrace();
                
                System.out.println(e); 
                }
      }
    }//GEN-LAST:event_checkAccountBtnActionPerformed

